import React, { useState, useRef } from 'react';
import {
    CContainer, CRow, CCol, CCard, CCardBody, CForm, CFormInput, CButton, CImage
} from '@coreui/react';
import { validateEmail } from '../../utils/utils';

const Login = () => {
    const [formValues, setFormValues] = useState({ email: '', password: '' });
    const emailErrorRef = useRef(null);
    const passwordErrorRef = useRef(null);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormValues({ ...formValues, [name]: value });
        if (name === 'email' && emailErrorRef.current) {
            emailErrorRef.current.style.display = 'none';
        }
        if (name === 'password' && passwordErrorRef.current) {
            passwordErrorRef.current.style.display = 'none';
        }
    };

    const validateForm = () => {
        let formIsValid = true;

        // Hide previous error messages
        if (emailErrorRef.current) {
            emailErrorRef.current.style.display = 'none';
        }
        if (passwordErrorRef.current) {
            passwordErrorRef.current.style.display = 'none';
        }

        // Validate email
        if (!formValues?.email) {
            if (emailErrorRef.current) {
                emailErrorRef.current.textContent = "Email is required";
                emailErrorRef.current.style.display = 'block';
            }
            formIsValid = false;
        }
        if (formValues?.email && !validateEmail(formValues?.email)) {
            if (emailErrorRef.current) {
                emailErrorRef.current.textContent = "Please enter a valid email";
                emailErrorRef.current.style.display = 'block';
            }
            formIsValid = false;
        }

        // Validate password
        if (!formValues?.password) {
            if (passwordErrorRef.current) {
                passwordErrorRef.current.textContent = "Password is required";
                passwordErrorRef.current.style.display = 'block';
            }
            formIsValid = false;
        }

        return formIsValid;
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (validateForm()) {
            // Handle login logic here
            console.log('Logging in with:', formValues);
        }
    };

    return (
        <CContainer fluid className="min-vh-100 d-flex align-items-center justify-content-center bg-purple">
            <CCard className="d-flex flex-row shadow-lg rounded-4 overflow-hidden" style={{ maxWidth: '900px', width: '100%' }}>
                <CCol md={6} className="d-none d-md-block">
                    <CImage
                        src="https://mdbcdn.b-cdn.net/img/Photos/new-templates/bootstrap-login-form/img1.webp"
                        alt="login"
                        className="w-100 h-100 object-fit-cover"
                    />
                </CCol>

                <CCol md={6} className="p-5 d-flex flex-column align-items-center">
                    <CCardBody className="w-100">
                        <div className="text-center mb-4">
                            <CImage
                                src="/assets/logo.jpeg"
                                alt="My College Vision"
                                className="img-fluid"
                                style={{ maxHeight: '200px' }}
                            />
                        </div>

                        <h4 className="text-center mb-4">Sign into your account</h4>

                        <CForm onSubmit={handleSubmit}>
                            <div className="mb-3">
                                <CFormInput
                                    type="email"
                                    name="email"
                                    label="Email address"
                                    value={formValues.email}
                                    onChange={handleChange}
                                    floatingLabel
                                />
                                <div ref={emailErrorRef} className="text-danger small mt-1" style={{ display: 'none' }}></div>
                            </div>

                            <div className="mb-4">
                                <CFormInput
                                    type="password"
                                    name="password"
                                    label="Password"
                                    value={formValues.password}
                                    onChange={handleChange}
                                    floatingLabel
                                />
                                <div ref={passwordErrorRef} className="text-danger small mt-1" style={{ display: 'none' }}></div>
                            </div>

                            <CButton color="dark" type="submit" className="w-100 mb-3" size="lg">
                                LOGIN
                            </CButton>

                            <div className="text-center">
                                <a href="#!" className="text-muted small">Forgot password?</a>
                                <p className="mt-3 mb-0">
                                    Don't have an account?{' '}
                                    <a href="#!" className="fw-bold text-decoration-none text-primary">
                                        Register here
                                    </a>
                                </p>
                            </div>
                        </CForm>

                        <div className="text-center mt-4">
                            <a href="#!" className="text-muted small me-3">Terms of use</a>
                            <a href="#!" className="text-muted small">Privacy policy</a>
                        </div>
                    </CCardBody>
                </CCol>
            </CCard>
        </CContainer>
    );
};

export default Login;
